SELECT scr.id, scr.student_id, scr.group_id, scr.enroll_status, scr.grade, scr.created_at, scr.updated_at FROM student_course_relations scr LEFT JOIN course_groups cg ON scr.group_id = cg.id WHERE scr.student_id = #{studentId}
AND cg.semester = #{semester}
ORDER BY scr.id DESC

